10	struct WorkspaceLayout {
11	    void* workspace;
12	
13	    int num_ranks;
14	    int num_scaleout_ranks, num_scaleup_ranks;
15	    int num_experts, num_experts_per_rank;
16	
17	    // We want to fix the layout position for all settings,
18	    // so that one buffer can be reused for all cases
19	    static constexpr int kNumMaxRanks = 1024;
20	    static constexpr int kNumMaxExperts = 2048;
21	    static constexpr int kNumMaxExpertsPerRank = 256;
22	    static constexpr int kNumMaxInflightAGRS = 32;
23	
24	    static constexpr int64_t kNumBarrierSignalBytes = 16;
25	
26	    __forceinline__ __device__ __host__
27	    WorkspaceLayout(void* workspace,
28	                    const int& num_scaleout_ranks,
29	                    const int& num_scaleup_ranks,
30	                    const int& num_experts):
31	        workspace(workspace),
32	        num_ranks(num_scaleout_ranks * num_scaleup_ranks),
33	        num_scaleout_ranks(num_scaleout_ranks),
34	        num_scaleup_ranks(num_scaleup_ranks),
35	        num_experts(num_experts) {
36	        num_experts_per_rank = num_experts / num_ranks;
37	        EP_UNIFIED_ASSERT(num_experts % num_ranks == 0);
38	        EP_UNIFIED_ASSERT(num_ranks <= kNumMaxRanks);
39	        EP_UNIFIED_ASSERT(num_experts <= kNumMaxExperts);
40	        EP_UNIFIED_ASSERT(num_experts_per_rank <= kNumMaxExpertsPerRank);
41	    }
42	
43	    static int64_t get_num_bytes() {
44	        // Pure NVLink scaleup barrier signals
45	        int64_t num_bytes = 0;
46	        num_bytes += kNumBarrierSignalBytes;
47	
48	        // Notify reduction workspace
49	        num_bytes += (kNumMaxRanks + kNumMaxExperts) * sizeof(int64_t);
50	
51	        // Scaleup notify threads
52	        // Rank send/recv count
53	        num_bytes += kNumMaxRanks * sizeof(int64_t) * 2;
54	        // Expert send/recv count
55	        num_bytes += kNumMaxExperts * sizeof(int64_t) * 2;
56	
57	        // Scaleup atomic sender count
58	        num_bytes += kNumMaxRanks * sizeof(int);
59	
60	        // Scaleout notify threads
61	        // Rank send/recv count
62	        num_bytes += kNumMaxRanks * sizeof(int) * 2;
63	        // Expert send/recv count
64	        num_bytes += kNumMaxExperts * sizeof(int) * 2;
65	
66	        // Scaleout channel metadata (finish flag and tails)
67	        num_bytes += kNumMaxRanks * kNumMaxChannels * sizeof(int64_t);
68	
69	        // Channel aggregated into the scaleup domains
70	        // Also reused for channel scaleup tail
71	        num_bytes += kNumMaxRanks * kNumMaxChannels * sizeof(int);
72	
73	        // Rank send/recv count, for PP prev/next ranks
74	        num_bytes += 2 * 2 * sizeof(int64_t);
75	
76	        // AGRS signals
77	        num_bytes += (kNumMaxInflightAGRS + 1) * kNumMaxRanks * sizeof(int);
78	
79	        return num_bytes;
80	    }
81	
82	    __forceinline__ __device__ __host__ unsigned long long* get_nvl_barrier_counter_ptr() const {
83	        return static_cast<unsigned long long*>(workspace);
84	    }
85	
86	    __forceinline__ __device__ __host__ int* get_nvl_barrier_signal_ptr(const int& phase) const {
87	        return math::advance_ptr<int>(workspace, (2 + phase) * sizeof(int));
88	    }
89	
90	    __forceinline__ __device__ __host__ int64_t* get_notify_reduction_workspace_ptr() const {
91	        return math::advance_ptr<int64_t>(workspace, kNumBarrierSignalBytes);
92	    }
93	
94	    template <bool kIsSendBuffer>
95	    __forceinline__ __device__ __host__ int64_t* get_scaleup_rank_expert_count_ptr() const {
96	        const auto base_ptr =
97	            math::advance_ptr<int64_t>(get_notify_reduction_workspace_ptr(), (kNumMaxRanks + kNumMaxExperts) * sizeof(int64_t));
98	        return base_ptr + (kIsSendBuffer ? 0 : kNumMaxRanks + kNumMaxExperts);
99	    }
100	
101	    template <bool kIsSendBuffer>
102	    __forceinline__ __device__ __host__ int64_t* get_scaleup_rank_count_ptr() const {
103	        return get_scaleup_rank_expert_count_ptr<kIsSendBuffer>();
104	    }
105	
106	    template <bool kIsSendBuffer>
107	    __forceinline__ __device__ __host__ int64_t* get_scaleup_expert_count_ptr() const {
108	        return get_scaleup_rank_expert_count_ptr<kIsSendBuffer>() + num_scaleup_ranks;
109	    }
110	
111	    __forceinline__ __device__ __host__ int* get_scaleup_atomic_sender_counter() const {
112	        return math::advance_ptr<int>(
113	            get_scaleup_rank_expert_count_ptr<true>(), 2 * (kNumMaxRanks + kNumMaxExperts) * sizeof(int64_t));
114	    }
115	
116	    template <bool kIsSendBuffer>
117	    __forceinline__ __device__ __host__ int* get_scaleout_rank_expert_count_ptr() const {
118	        const auto base_ptr =
119	            math::advance_ptr<int>(get_scaleup_atomic_sender_counter(), kNumMaxRanks * sizeof(int));
120	        return base_ptr + (kIsSendBuffer ? 0 : kNumMaxRanks + kNumMaxExperts);
121	    }
122	
123	    template <bool kIsSendBuffer>
124	    __forceinline__ __device__ __host__ int* get_scaleout_rank_count_ptr(
125	        const int& scaleout_rank_idx = 0, const int& scaleup_rank_idx = 0) const {
126	        const auto base_ptr = get_scaleout_rank_expert_count_ptr<kIsSendBuffer>();
127	        return base_ptr + scaleout_rank_idx * num_scaleup_ranks + scaleup_rank_idx;
128	    }
129	
130	    template <bool kIsSendBuffer>
131	    __forceinline__ __device__ __host__ int* get_scaleout_expert_count_ptr(
132	        const int& scaleout_rank_idx = 0, const int& expert_idx = 0) const {
133	        const auto base_ptr = get_scaleout_rank_expert_count_ptr<kIsSendBuffer>() + num_ranks;
134	        return base_ptr + scaleout_rank_idx * (num_scaleup_ranks * num_experts_per_rank) + expert_idx;
135	    }
136	
137	    __forceinline__ __device__ __host__ int64_t* get_scaleout_channel_signaled_tail_ptr(
138	        const int& channel_idx, const int& scaleout_rank_idx) const {
139	        const auto base_ptr = math::advance_ptr<int64_t>(
140	            get_scaleout_rank_expert_count_ptr<true>(),
141	            (kNumMaxRanks + kNumMaxExperts) * sizeof(int) * 2);
142	        return base_ptr + (channel_idx * num_scaleout_ranks + scaleout_rank_idx);
143	    }
144	
145	    __forceinline__ __device__ __host__ int* get_channel_scaleup_tail_ptr(
146	        const int& channel_idx, const int& scaleup_rank_idx) const {
147	        const auto base_ptr = math::advance_ptr<int>(
148	            get_scaleout_channel_signaled_tail_ptr(0, 0),
149	            kNumMaxRanks * kNumMaxChannels * sizeof(int64_t));
150	        return base_ptr + (channel_idx * num_scaleup_ranks + scaleup_rank_idx);
151	    }
152	
153	    __forceinline__ __device__ __host__ int64_t* get_pp_send_count_ptr(const int& offset) const {
154	        const auto base_ptr = math::advance_ptr<int64_t>(
155	            get_channel_scaleup_tail_ptr(0, 0),
156	            kNumMaxRanks * kNumMaxChannels * sizeof(int));
157	        return base_ptr + offset;
158	    }
159	
160	    __forceinline__ __device__ __host__ int64_t* get_pp_recv_count_ptr(const int& offset) const {
161	        const auto base_ptr = math::advance_ptr<int64_t>(
162	            get_pp_send_count_ptr(0), 2 * sizeof(int64_t));
163	        return base_ptr + offset;
164	    }
165	
166	    __forceinline__ __device__ __host__ int* get_agrs_recv_signal_ptr(const int& slot, const int& rank_idx) const {
167	        const auto base_ptr = math::advance_ptr<int>(
168	            get_pp_recv_count_ptr(0), 2 * sizeof(int64_t));
169	        return base_ptr + slot * kNumMaxRanks + rank_idx;
170	    }
171	
172	    __forceinline__ __device__ __host__ int* get_agrs_session_signal_ptr(const int& rank_idx) const {
173	        const auto base_ptr = math::advance_ptr<int>(
174	            get_agrs_recv_signal_ptr(0, 0), kNumMaxInflightAGRS * kNumMaxRanks * sizeof(int));
175	        return base_ptr + rank_idx;
176	    }
177	};
178	
179	struct TokenLayout {
180	    int num_hidden_bytes, num_sf_bytes;
181	    // NOTES: the top-k index is always 32-bit
182	    bool with_metadata;
183	    int num_topk, num_metadata_bytes;
184	    void* base;
185	
186	    __forceinline__ __device__ __host__
187	    TokenLayout(const int& num_hidden_bytes, const int& num_sf_bytes,
188	                const int& num_topk, const bool& with_metadata, void* base = nullptr) :
189	        num_hidden_bytes(num_hidden_bytes),
190	        num_sf_bytes(num_sf_bytes),
191	        // Metadata includes: top-k indices, weight and source rank/token index
192	        with_metadata(with_metadata),
193	        num_topk(num_topk),
194	        num_metadata_bytes(num_topk * (sizeof(int) + sizeof(float)) +
195	                           (with_metadata ? (1 + num_topk) * sizeof(int) : 0)),
196	        base(base) {
197	        EP_STATIC_ASSERT(sizeof(int) == sizeof(float), "Invalid size assumption");
198	        EP_UNIFIED_ASSERT(num_hidden_bytes % ptx::kNumTMAAlignBytes == 0);
199	    }
200	
201	    template <bool kWithMBarrier, typename dtype_t = int>
202	    __forceinline__ __device__ __host__ dtype_t get_num_bytes() const {
203	        const auto num_bytes = math::align(num_hidden_bytes, ptx::kNumTMAAlignBytes) +
204	                               math::align(num_sf_bytes, ptx::kNumTMAAlignBytes) +
205	                               math::align(num_metadata_bytes, ptx::kNumTMAAlignBytes) +
206	                               math::align<int>(kWithMBarrier ? sizeof(ptx::mbarrier) : 0, ptx::kNumTMAAlignBytes);
207	        return static_cast<dtype_t>(num_bytes);
208	    }
209	
210	    __forceinline__ __device__ __host__ void* get_base_ptr() const {
211	        return base;
212	    }
213	
214	    __forceinline__ __device__ __host__ void set_base_ptr(void* ptr) {
215	        base = ptr;
216	    }
217	
218	    __forceinline__ __device__ __host__ void* get_hidden_ptr() const {
219	        return get_base_ptr();
220	    }
221	
222	    __forceinline__ __device__ __host__ sf_pack_t* get_sf_ptr() const {
223	        return math::advance_ptr<sf_pack_t>(base, math::align(num_hidden_bytes, ptx::kNumTMAAlignBytes));
224	    }
225	
226	    __forceinline__ __device__ __host__ int* get_metadata_ptr() const {
227	        return math::advance_ptr<int>(get_sf_ptr(), math::align(num_sf_bytes, ptx::kNumTMAAlignBytes));
228	    }
229	
230	    __forceinline__ __device__ __host__ int* get_topk_idx_ptr() const {
231	        return get_metadata_ptr();
232	    }
233	
234	    __forceinline__ __device__ __host__ float* get_topk_weights_ptr() const {
235	        return math::advance_ptr<float>(get_metadata_ptr(), num_topk * sizeof(int));
236	    }
237	
238	    __forceinline__ __device__ __host__ int* get_src_token_global_idx_ptr() const {
239	        return math::advance_ptr<int>(get_topk_weights_ptr(), num_topk * sizeof(float));
240	    }
241	
242	    __forceinline__ __device__ __host__ int* get_linked_list_idx_ptr() const {
243	        return get_src_token_global_idx_ptr() + 1;
244	    }
245	
246	    __forceinline__ __device__ ptx::mbarrier* get_mbarrier_ptr() const {
247	        return math::advance_ptr<ptx::mbarrier>(get_metadata_ptr(), math::align(num_metadata_bytes, ptx::kNumTMAAlignBytes));
248	    }
249	};
250	
251	template <bool kWithMBarrier>
252	struct BufferLayout {
253	    TokenLayout token_layout;
254	    int num_ranks;
255	    int num_max_tokens_per_rank;
256	
257	    void* base;
258	
259	    __forceinline__ __device__ __host__
260	    BufferLayout(const TokenLayout& token_layout,
261	                 const int& num_ranks,
262	                 const int& max_num_tokens_per_rank,
263	                 void* base = nullptr) :
264	        token_layout(token_layout),
265	        num_ranks(num_ranks), num_max_tokens_per_rank(max_num_tokens_per_rank),
266	        base(base) {}
267	
268	    __forceinline__ __device__ __host__
269	    int64_t get_num_bytes_per_token() const {
270	        return token_layout.get_num_bytes<kWithMBarrier, int64_t>();
271	    }
272	
273	    __forceinline__ __device__ __host__
274	    int64_t get_num_bytes_per_rank() const {
275	        return num_max_tokens_per_rank * get_num_bytes_per_token();
276	    }
277	
278	    __forceinline__ __device__ __host__
279	    int64_t get_num_bytes() const {
280	        return get_num_bytes_per_rank() * num_ranks;
281	    }
282	
283	    __forceinline__ __device__ __host__
284	    void* get_buffer_end_ptr() const {
285	        return math::advance_ptr(base, get_num_bytes());
286	    }
287	
288	    __forceinline__ __device__ __host__
289	    BufferLayout get_rank_buffer(const int& rank_idx) const {
290	        return BufferLayout(token_layout,
291	                            1, num_max_tokens_per_rank,
292	                            static_cast<int8_t*>(base) + get_num_bytes_per_rank() * rank_idx);
293	    }
294	
295	    template <int kNumTokensPerChannel>
296	    __forceinline__ __device__ __host__
297	    BufferLayout get_channel_buffer(const int& channel_idx) const {
298	        EP_UNIFIED_ASSERT(num_max_tokens_per_rank % kNumTokensPerChannel == 0);
299	        return BufferLayout(token_layout,
300	                            // Do not use `num_max_tokens_per_rank / kNumTokensPerChannel` as the false stride
301	                            num_ranks, num_max_tokens_per_rank,
302	                            static_cast<int8_t*>(base) + get_num_bytes_per_token() * kNumTokensPerChannel * channel_idx);
303	    }
304	
305	    __forceinline__ __device__ __host__
306	    TokenLayout get_token_buffer(const int& token_idx, const bool& global = false) const {
307	        EP_UNIFIED_ASSERT(num_ranks == 1 or global);
308	        return TokenLayout(token_layout.num_hidden_bytes, token_layout.num_sf_bytes, token_layout.num_topk, token_layout.with_metadata,
309	                           static_cast<int8_t*>(base) + token_layout.get_num_bytes<kWithMBarrier, int64_t>() * token_idx);
310	    }
311	};
312	
313	}  // namespace deep_ep::elastic
