19	class ElasticBuffer {
20	    // Buffer bytes = GPU buffer + CPU buffer (excludes workspace)
21	    // Memory layout: [[[Workspace] GPU buffer] CPU buffer]
22	    int64_t num_buffer_bytes;
23	    int64_t num_gpu_buffer_bytes;
24	    int64_t num_cpu_buffer_bytes;
25	    void* buffer;
26	
27	    // Destructor settings
28	    bool explicitly_destroy;
29	    bool destroyed = false;
30	
31	    // Workspace
32	    // NOTES: for all workspace, we must keep them as zeros
33	    void *workspace;
34	    void *host_workspace, *mapped_host_workspace;
35	    std::shared_ptr<layout::WorkspaceLayout> workspace_layout_wo_expert;
36	
37	    // CUDA streams
38	    at::cuda::CUDAStream comm_stream;
39	
40	    // Whether to use hybrid mode (scale-out with scale-up)
41	    bool allow_hybrid_mode;
42	
43	    // Whether to allow multiple reductions
44	    bool allow_multiple_reduction;
45	
46	    // Whether to prefer overlapping communication with compute (use more SMs and channels if false)
47	    bool prefer_overlap_with_compute;
48	
49	    // Timeout settings
50	    int num_cpu_timeout_secs;
51	    int64_t num_gpu_timeout_cycles;
52	
53	    // NCCL context
54	    std::shared_ptr<nccl::NCCLSymmetricMemoryContext> nccl_context;
55	
56	    // Some EP hybrid mode settings
57	    static constexpr int kNumMaxChannelsPerSM = 8;
58	    static constexpr int kNumMaxSMs = 160;
59	    static constexpr int kNumMaxChannels = kNumMaxChannelsPerSM * kNumMaxSMs;
60	
61	    // Some Engram storage settings
62	    int num_engram_entries = 0, engram_hidden = 0;
63	    std::optional<torch::Tensor> engram_sf;
64	
65	    // PP settings
66	    int prev_rank_idx = 0, next_rank_idx = 0;
67	    int64_t num_max_pp_tensor_bytes = 0;
68	    int num_max_pp_inflight_tensors = 0;
69	
70	    // AGRS session settings
71	    int64_t num_max_agrs_session_bytes = 0;
72	    int num_max_agrs_per_session = 0;
73	    int agrs_session_idx = 0;
74	    bool agrs_in_session = false;
75	
