1347	    pybind11::class_<ElasticBuffer>(m, "ElasticBuffer")
1348	        .def(pybind11::init<int, int, int64_t, symmetric::cpu_comm_t, int64_t, int64_t, bool, bool, bool, int, int, int, int, bool>())
